  -- ---- Sections & paragraphs ----

  -- Section: Do different parts of the brain do different things?
  INSERT INTO sections (module_id, title, slug, order_index)
  VALUES (v_module_id, 'Do different parts of the brain do different things?', 'do-different-parts', v_next_order)
