  v_next_order := v_next_order + 1;
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "In Hellenic Greece, Herophilus and Erasistratus were the first to separate sensory from motor nerves, but this didn’t provide much insight into whether different functions of the mind were restricted to specific parts of the brain. Nonetheless, Herophilus is thought to have written about specific parts of the brain serving different functions; Erasistratus is said to have associated cerebellar size with running speed and coordination and the complexity of cerebral convolutions with intellect"}, {"type": "citation_ref", "number": 8}, {"type": "text", "content": "."}]}'::JSONB, 'In Hellenic Greece, Herophilus and Erasistratus were the first to separate sensory from motor nerves, but this didn’t provide much insight into whether different functions of the mind were restricted to specific parts of the brain. Nonetheless, Herophilus is thought to have written about specific parts of the brain serving different functions; Erasistratus is said to have associated cerebellar size with running speed and coordination and the complexity of cerebral convolutions with intellect.', 0, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "In Rome, Galen made several contributions to the idea of localization of nervous system function. First, he argued that since the cerebrum is relatively soft, it likely receives sensory nerves, whereas since the cerebellum is relatively hard, it must receive motor nerves. Second, based on vivisections in animals he was able to provide evidence for localization of function in the central nervous system (CNS). In one set of experiments in which he sought to identify the nerve responsible for breathing, he instead found the laryngeal nerve. In a public dissection, he proceeded to show that he could stop a pig from squealing by specifically cutting this nerve"}, {"type": "citation_ref", "number": 20}, {"type": "text", "content": " ("}, {"type": "figure_placeholder", "number": 5}, {"type": "text", "content": "). In another set of experiments Galen cut the spinal cord of animals in various locations"}, {"type": "citation_ref", "number": 21}, {"type": "text", "content": ". He found that for full transections, everything below the cut became paralyzed. In contrast, if he cut the spinal cord from the side, and only halfway through, only the parts of the body below and ipsilateral to the cut were paralyzed."}]}'::JSONB, 'In Rome, Galen made several contributions to the idea of localization of nervous system function. First, he argued that since the cerebrum is relatively soft, it likely receives sensory nerves, whereas since the cerebellum is relatively hard, it must receive motor nerves. Second, based on vivisections in animals he was able to provide evidence for localization of function in the central nervous system (CNS). In one set of experiments in which he sought to identify the nerve responsible for breathing, he instead found the laryngeal nerve. In a public dissection, he proceeded to show that he cou', 1, true, v_fig_5, 'auto', false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Galen had less to work with when it came to assigning mental faculties to specific parts of the brain. As such, while he split the mental faculties into three components—imagination, reasoning, and memory—he did not propose specific brain locations where these were processed. That task would be taken up by Christian Church Fathers of the 4<sup>th</sup> century CE. They took these faculties and assigned each to a different ventricle in the brain. Since brain activity was thought to arise via pneuma or spirits (i.e., some type of air-like substance) flowing through nerves, the ventricles seemed like a good place for the pneuma to be stored and work their magic. This theory, referred to as the cell doctrine or ventricular theory, would persist in variations—some with more ventricles, some with different functions assigned to different ventricles—for the next thousand years"}, {"type": "citation_ref", "number": 8}, {"type": "citation_ref", "number": 22}, {"type": "citation_ref", "number": 23}, {"type": "text", "content": " ("}, {"type": "figure_placeholder", "number": 6}, {"type": "text", "content": "). In general, sensory signals were thought to be received by the most frontal ventricle. From there, pneuma would be passed onto the middle ventricle for mental processing, and then the pneuma would pass to the most anterior ventricle for mental storage."}]}'::JSONB, 'Galen had less to work with when it came to assigning mental faculties to specific parts of the brain. As such, while he split the mental faculties into three components—imagination, reasoning, and memory—he did not propose specific brain locations where these were processed. That task would be taken up by Christian Church Fathers of the 4th century CE. They took these faculties and assigned each to a different ventricle in the brain. Since brain activity was thought to arise via pneuma or spirits (i.e., some type of air-like substance) flowing through nerves, the ventricles seemed like a good', 2, true, v_fig_6, 'auto', false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "It wasn’t until about a thousand years after the death of Galen that sufficient advancements were made in neuroanatomy to allow for more pointed ideas to arise about localization of brain function. Modern neuroanatomy can be traced back to Andreas Vesalius (1512-1564) who combined art and science in the early Renaissance to produce beautiful anatomical descriptions of the human body. His work relied on dissecting human corpses, but this was just starting to be allowed in some parts of Europe at the time. As such, sometimes Vesalius had to acquire his material in creative ways, such as getting bodies fresh from the gallows"}, {"type": "citation_ref", "number": 24}, {"type": "text", "content": ". In his magnum opus <em>De Humani Corporis Fabrica</em> (1543; often referred to simply as <em>De Fabrica</em>; "}, {"type": "figure_placeholder", "number": 7}, {"type": "text", "content": "), Vesalius provided unparalleled artistic renditions of the human brain: it’s believed the woodcut artwork was produced by students of Titian. In <em>De Fabrica</em>, Vesalius pinpointed numerous errors in Galen’s work, much of which likely arose since Galen did not have access to human tissue. Vesalius’ work was widely read and served as a foundation for future neuroanatomists to scrutinize and refine"}, {"type": "citation_ref", "number": 25}, {"type": "text", "content": ". This was the case for Thomas Willis (1621-1675), who built on Vesalius’ anatomical work and combined it with findings from his clinical practice to produce the book <em>Cerebri Anatome</em> (1664), the most complete and detailed description of the nervous system at the time"}, {"type": "citation_ref", "number": 26}, {"type": "text", "content": ". Willis was the first to describe the anatomy of the striatum and discovered the arterial circle at the base of the brain which bears his name to this day—the circle of Willis. Willis also coined the term neurology. Thus, by the 17<sup>th</sup> century it was clear that the brain had a complex anatomical structure, with distinct regions and connectivity patterns. This led people to start proposing specific roles for these newly described anatomical regions. Thomas Willis, for instance, proposed that common sense was housed in the striatum, imagination in the corpus collosum, and memory in the cortex"}, {"type": "citation_ref", "number": 27}, {"type": "text", "content": "."}]}'::JSONB, 'It wasn’t until about a thousand years after the death of Galen that sufficient advancements were made in neuroanatomy to allow for more pointed ideas to arise about localization of brain function. Modern neuroanatomy can be traced back to Andreas Vesalius (1512-1564) who combined art and science in the early Renaissance to produce beautiful anatomical descriptions of the human body. His work relied on dissecting human corpses, but this was just starting to be allowed in some parts of Europe at the time. As such, sometimes Vesalius had to acquire his material in creative ways, such as getting ', 3, true, v_fig_7, 'auto', false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "René Descartes, a contemporary of Willis, put forward a different theory of localization of function based on the concept of dualism—that the human body is effectively just an automaton that needs to interact with an ethereal soul in order to be controlled"}, {"type": "citation_ref", "number": 28}, {"type": "text", "content": ". Descartes argued that the pineal gland, which lies along the midline, acted like a puppet master, directing the flow of spirits throughout the brain to control distinct functions, and acting as an interface between the physical and ethereal worlds. However, unlike Willis, Descartes was neither a clinician nor an anatomist, and he incorrectly believed the pineal gland was located at the top of a ventricle. Interestingly, a similar idea about the pineal gland had been proposed hundreds of years earlier by Herophilus, but Galen wrote that “the notion that the pineal body is what regulates the passage of the pneuma is the opinion of those who are ignorant… Why need I mention how ignorant and stupid these opinions are.”"}, {"type": "citation_ref", "number": 28}]}'::JSONB, 'René Descartes, a contemporary of Willis, put forward a different theory of localization of function based on the concept of dualism—that the human body is effectively just an automaton that needs to interact with an ethereal soul in order to be controlled. Descartes argued that the pineal gland, which lies along the midline, acted like a puppet master, directing the flow of spirits throughout the brain to control distinct functions, and acting as an interface between the physical and ethereal worlds. However, unlike Willis, Descartes was neither a clinician nor an anatomist, and he incorrectl', 4, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Despite these emerging claims of localization of function, there were those who pushed back. For instance, Danish anatomist and geologist Neils Steensen argued that Descartes’ anatomical positioning of the pineal gland was incorrect, finding from his own dissections that the pineal gland was embedded in brain tissue. This meant it could not move around freely in the ventricle as Descartes had proposed"}, {"type": "citation_ref", "number": 27}, {"type": "text", "content": ". Regarding Thomas Willis, Steensen believed that Willis also lacked sufficient evidence to assign function to specific brain areas. Related to Willis’ suggestion that the corpus collosum housed imagination, Steensen wrote, “We know so little of the true structure of the corpus callosum that a man of tolerable genius may say about it, whatever he pleases"}, {"type": "citation_ref", "number": 27}, {"type": "text", "content": ".” Steensen argued that only evidence-based reasoning would move the field forward, and that at the time there was not enough evidence to draw many conclusions."}]}'::JSONB, 'Despite these emerging claims of localization of function, there were those who pushed back. For instance, Danish anatomist and geologist Neils Steensen argued that Descartes’ anatomical positioning of the pineal gland was incorrect, finding from his own dissections that the pineal gland was embedded in brain tissue. This meant it could not move around freely in the ventricle as Descartes had proposed. Regarding Thomas Willis, Steensen believed that Willis also lacked sufficient evidence to assign function to specific brain areas. Related to Willis’ suggestion that the corpus collosum housed i', 5, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "It turns out there was someone taking such an evidence-based approach to studying brain function in the mid-17<sup>th</sup> century: Swedish polymath Emanuel Swedenborg. By reading everything he could find about anatomy and medical cases involving brain damage, he correctly deduced the general location of motor cortex and assigned roles related to executive function to the frontal lobes. However, most of his writings about the brain were not published in his lifetime, as he started having spiritual visions and turned his attention to religious writings"}, {"type": "citation_ref", "number": 29}, {"type": "citation_ref", "number": 30}, {"type": "text", "content": ". The New Church, or Swedenborgianism, sprung up after his death. In an interesting parallel, Niels Steensen also became increasingly religious in his later years and stopped focusing on natural sciences. Steensen became a priest, then a vicar, then a bishop, and some 300 years after his death was beatified by the Catholic Church—the closest any neuroscientist has come to becoming a saint."}]}'::JSONB, 'It turns out there was someone taking such an evidence-based approach to studying brain function in the mid-17th century: Swedish polymath Emanuel Swedenborg. By reading everything he could find about anatomy and medical cases involving brain damage, he correctly deduced the general location of motor cortex and assigned roles related to executive function to the frontal lobes. However, most of his writings about the brain were not published in his lifetime, as he started having spiritual visions and turned his attention to religious writings. The New Church, or Swedenborgianism, sprung up afte', 6, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "As the 18<sup>th</sup> century commenced, gross neuroanatomy was relatively well established, but still practically nothing was known regarding functional organization. In the middle of the 18<sup>th</sup> century, Albrecht von Haller performed a series of influential experiments related to sensibility and irritability:"}]}'::JSONB, 'As the 18th century commenced, gross neuroanatomy was relatively well established, but still practically nothing was known regarding functional organization. In the middle of the 18th century, Albrecht von Haller performed a series of influential experiments related to sensibility and irritability:', 7, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "blockquote", "content": "“I call that part of the human body irritable, which becomes shorter upon being touched; very irritable if it contracts upon a slight touch, and the contrary if by a violent touch it contracts but little. I call that a sensible part of the human body, which upon being touched transmits the impression of it to the soul; and in brutes, in whom the existence of a soul is not so clear, I call those parts sensible, the Irritation of which occasions evident signs of pain and disquiet in the animal.<sup>31</sup>”"}]}'::JSONB, '', 8, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Haller concluded that only muscles were irritable, and that only parts of the body connected to nerves showed sensibility"}, {"type": "citation_ref", "number": 31}, {"type": "text", "content": ". He also argued that grey matter was insensitive and that only physical stimulation of the white matter elicited movements"}, {"type": "citation_ref", "number": 31}, {"type": "text", "content": ". As such, he considered the white matter to be the brain’s seat of sensations, but that various parts of white matter throughout the brain were functionally equivalent, or equipotential"}, {"type": "citation_ref", "number": 32}, {"type": "text", "content": "."}]}'::JSONB, 'Haller concluded that only muscles were irritable, and that only parts of the body connected to nerves showed sensibility. He also argued that grey matter was insensitive and that only physical stimulation of the white matter elicited movements. As such, he considered the white matter to be the brain’s seat of sensations, but that various parts of white matter throughout the brain were functionally equivalent, or equipotential.', 9, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Ideas surrounding equipotentiality would be challenged around the turn of the 19<sup>th</sup> century. Franz Joseph Gall, a German physician and anatomist who worked in Austria, then later in France, believed that different parts of the brain served different functions, that the relative size of each of these functional areas differed across individuals, and that these anatomical differences accounted for differences in disposition. Moreover, he thought that these local excesses or deficiencies in brain size could be read out through external measurement of the skull, reasoning that “the skull is molded on the brain"}, {"type": "citation_ref", "number": 32}, {"type": "text", "content": ".” In the first decade of the 1800s he travelled through Europe promoting his ideas about “organology” or “cranioscopy,” which at its heart was just a twist on the old idea of physiognomy—the belief that a person’s character could be inferred from facial features."}]}'::JSONB, 'Ideas surrounding equipotentiality would be challenged around the turn of the 19th century. Franz Joseph Gall, a German physician and anatomist who worked in Austria, then later in France, believed that different parts of the brain served different functions, that the relative size of each of these functional areas differed across individuals, and that these anatomical differences accounted for differences in disposition. Moreover, he thought that these local excesses or deficiencies in brain size could be read out through external measurement of the skull, reasoning that “the skull is molded ', 10, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Though a leading neuroanatomist of his time—for instance, Gall found that white matter fibers originated from grey matter, and he described how spinal nerves connected with the midbrain, which then connected with other brain areas"}, {"type": "citation_ref", "number": 32}, {"type": "text", "content": "—Gall did not think that brain anatomy was particularly informative to function: “it is thus without the help of any anatomical dissection that we have ourselves made most of our physiological discoveries [“physiological” here means functional]."}, {"type": "citation_ref", "number": 32}, {"type": "text", "content": "” To assign specific faculties to specific brain regions, Gall, along with his assistant Johann Spurzheim, took humans with known skills (e.g., good memory) or behavioral excesses (e.g., violent murderers), and contrasted them with humans lacking such traits. Gall and Spurzheim generated a map outlining the location of over twenty-five brain regions underlying different faculties ("}, {"type": "figure_placeholder", "number": 8}, {"type": "text", "content": "). Gall and Spurzheim eventually had a falling out, and Spurzheim would then coin the term phrenology, add a few more functional brain areas, and help to popularize phrenology internationally"}, {"type": "citation_ref", "number": 8}, {"type": "text", "content": "."}]}'::JSONB, 'Though a leading neuroanatomist of his time—for instance, Gall found that white matter fibers originated from grey matter, and he described how spinal nerves connected with the midbrain, which then connected with other brain areas —Gall did not think that brain anatomy was particularly informative to function: “it is thus without the help of any anatomical dissection that we have ourselves made most of our physiological discoveries [“physiological” here means functional]. ” To assign specific faculties to specific brain regions, Gall, along with his assistant Johann Spurzheim, took humans with', 11, true, v_fig_8, 'auto', false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Phrenology became wildly popular, and phrenological societies popped up throughout the world. It was used to argue for social reforms (e.g., to encourage the development of morally favourable faculties)"}, {"type": "citation_ref", "number": 32}, {"type": "text", "content": ". However, seeing as, unlike Gall’s neuroanatomical work, his “organology” work was built on much shakier ground, it was immediately attacked. On political and religious grounds, some people did not appreciate that his materialistic ideas took what many viewed as a spiritual and ethereal mind/soul and placed it firmly in corruptible tissue. On scientific grounds, Gall’s most famous critic was Marie Pierre Jean Flourens. In part via a commission by the French Académie de Sciences that wanted to undercut Gall’s ideas"}, {"type": "citation_ref", "number": 32}, {"type": "text", "content": ", Flourens performed a number of experiments, mostly in pigeons and rabbits, where he lesioned specific brain regions and studied the impact on behavior. Flourens found that different parts of the brain served distinct functions. The medulla was critical for breathing. The cerebellum appeared important for motor coordination. The cerebrum was critical for “perception, judgement and will."}, {"type": "citation_ref", "number": 19}, {"type": "text", "content": "” As noted above, this was the first solid evidence that the brain housed the mind. However, in contrast to Gall, Flourens considered the cerebrum to be equipotential: “All sensations, all perceptions, and all volition occupy concurrently the same seat in these organs. The faculty of sensation, perception, and volition is then essentially one faculty."}, {"type": "citation_ref", "number": 33}, {"type": "text", "content": "” Thus, Flourens concluded that phrenology was nonsense."}]}'::JSONB, 'Phrenology became wildly popular, and phrenological societies popped up throughout the world. It was used to argue for social reforms (e.g., to encourage the development of morally favourable faculties). However, seeing as, unlike Gall’s neuroanatomical work, his “organology” work was built on much shakier ground, it was immediately attacked. On political and religious grounds, some people did not appreciate that his materialistic ideas took what many viewed as a spiritual and ethereal mind/soul and placed it firmly in corruptible tissue. On scientific grounds, Gall’s most famous critic was Ma', 12, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Still, the work of Flourens was very influential, and localization of brain function became a controversial topic, with many people holding strong opinions despite a continued lack of solid evidence one way or another. Then, in April 1861, a patient by the name of Louis Victor Leborgne came under the care of physician Paul Broca (whom we already met above in the section about trepanation). Leborgne had been hospitalized for the previous 10 years, stemming from epilepsy that started in his youth and had eventually led, by the age of 30, to aphasia—an inability to speak"}, {"type": "citation_ref", "number": 34}, {"type": "citation_ref", "number": 35}, {"type": "text", "content": ". By the time Broca saw him, Leborgne was known as “Tan,” as this was essentially the only word he could say, often repeated twice in a row. Leborgne’s mind otherwise appeared intact—he could understand what was said to him and answer questions with gestures. At the time, in France, there were active discussions about whether there was a cortical locus for speech. Years earlier, physician Jean-Baptiste Bouillaud had described patients with anterior lobe damage who had trouble generating speech. Furthermore, a few days before Leborgne came under Broca’s care, at a Paris scientific meeting, physician Simon Auburtin, Bouillaud’s son-in-law, discussed a patient of his who had a skull opening over the anterior lobe due to a gunshot wound: “During the interrogation the blade of a large spatula was placed on the anterior lobes; by means of light pressure speech was suddenly stopped; a word that had been commenced was cut in two. The faculty of speech reappeared as soon as the compression ceased."}, {"type": "citation_ref", "number": 36}, {"type": "text", "content": "” Leborgne died a few days after coming under Broca’s care and an autopsy revealed significant damage to the frontal cortex in the left hemisphere ("}, {"type": "figure_placeholder", "number": 9}, {"type": "text", "content": "). Broca published this result to immediate enthusiasm from the medical and scientific communities, and a few years later published a follow-up paper with several additional people with aphasia, solidifying his claim of the left frontal cortex as the locus of speech generation"}, {"type": "citation_ref", "number": 37}, {"type": "text", "content": "."}]}'::JSONB, 'Still, the work of Flourens was very influential, and localization of brain function became a controversial topic, with many people holding strong opinions despite a continued lack of solid evidence one way or another. Then, in April 1861, a patient by the name of Louis Victor Leborgne came under the care of physician Paul Broca (whom we already met above in the section about trepanation). Leborgne had been hospitalized for the previous 10 years, stemming from epilepsy that started in his youth and had eventually led, by the age of 30, to aphasia—an inability to speak. By the time Broca saw hi', 13, true, v_fig_9, 'auto', false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "The next breakthrough came in the early 1870s. Working in Berlin, neurologist Eduard Fritsch and anatomist Gustav Hitzig used electrical stimulation of cortex in dogs to identify motor cortex. Not only did they find a specific portion of cortex that could reliably drive contralateral body movements, they found that stimulating different parts of this motor cortex led to movement of different parts of the body (e.g., hind leg vs. front leg; "}, {"type": "figure_placeholder", "number": 10}, {"type": "text", "content": ")"}, {"type": "citation_ref", "number": 38}, {"type": "text", "content": ". Fritsch and Hitzig then showed that lesioning this region led to contralateral motor deficits."}]}'::JSONB, 'The next breakthrough came in the early 1870s. Working in Berlin, neurologist Eduard Fritsch and anatomist Gustav Hitzig used electrical stimulation of cortex in dogs to identify motor cortex. Not only did they find a specific portion of cortex that could reliably drive contralateral body movements, they found that stimulating different parts of this motor cortex led to movement of different parts of the body (e.g., hind leg vs. front leg; (Figure 10)). Fritsch and Hitzig then showed that lesioning this region led to contralateral motor deficits.', 14, true, v_fig_10, 'auto', false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Fritsch and Hitzig’s work was validated soon afterwards in primates by David Ferrier who was working in England. However, not everyone was convinced. A flashpoint in the debate between localizationalists and anti-localizationalists occurred at the Seventh International Medical Congress, held in 1881 in London. In attendance were 3,000 people, including clinicians and researchers, as well as political, religious and intellectual leaders"}, {"type": "citation_ref", "number": 39}, {"type": "text", "content": ". One morning, Leopold Goltz, a German physiologist, presented one of the dogs he had worked with. Goltz claimed that, using a water pick, he had ablated motor cortex from one of the hemispheres, but the dog still moved around more or less normally. Immediately afterward, Ferrier presented one of his monkeys that had motor cortex ablated in one hemisphere. This monkey presented with hemiplegia on the contralateral side of the lesion. How could such conflicting results be assessed? Goltz and Ferrier agreed for an independent panel of experts, including a young Charles Sherrington, to euthanize the animals and examine the extent of brain damage in relation to the claims of purported lesions by Goltz and Ferrier"}, {"type": "citation_ref", "number": 40}, {"type": "text", "content": ". In the end, it was found that Goltz’s dog had significant portions of motor cortex remaining, whereas Ferrier’s monkey had a lesion corresponding to Ferrier’s description"}, {"type": "citation_ref", "number": 39}, {"type": "text", "content": " ("}, {"type": "figure_placeholder", "number": 11}, {"type": "text", "content": "). Nonetheless, subsequent work would show more notable deficits in primates lacking motor cortex than in lower mammals with similar lesions, providing at least some support to Goltz."}]}'::JSONB, 'Fritsch and Hitzig’s work was validated soon afterwards in primates by David Ferrier who was working in England. However, not everyone was convinced. A flashpoint in the debate between localizationalists and anti-localizationalists occurred at the Seventh International Medical Congress, held in 1881 in London. In attendance were 3,000 people, including clinicians and researchers, as well as political, religious and intellectual leaders. One morning, Leopold Goltz, a German physiologist, presented one of the dogs he had worked with. Goltz claimed that, using a water pick, he had ablated motor c', 15, true, v_fig_11, 'auto', false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "By the turn of the 20<sup>th</sup> century, while researchers increasingly believed that there were cortical loci for primary sensory and motor areas, it remained controversial whether there was localization of higher brain functions. For roughly a 30-year period in the mid-20<sup>th</sup> century, Karl Lashley, an American behavioral psychologist, hunted for engrams—the physical traces of stored memories in the brain. He trained rats in mazes and memory tasks, and then lesioned various brain regions, largely in cortex, and examined the effects. He was unable to find a specific part of the brain that stored memories. This led him to conclude that unlike primary sensory cortical regions which took up defined plots of land in the brain, memories were stored everywhere (equipotentiality) and that the impact of lesions directly scaled with the size of the lesion (mass action)"}, {"type": "citation_ref", "number": 41}, {"type": "text", "content": "."}]}'::JSONB, 'By the turn of the 20th century, while researchers increasingly believed that there were cortical loci for primary sensory and motor areas, it remained controversial whether there was localization of higher brain functions. For roughly a 30-year period in the mid-20th century, Karl Lashley, an American behavioral psychologist, hunted for engrams—the physical traces of stored memories in the brain. He trained rats in mazes and memory tasks, and then lesioned various brain regions, largely in cortex, and examined the effects. He was unable to find a specific part of the brain that stored memorie', 16, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Lashley’s conclusions on a lack of localization of function for memory processing didn’t hold for long. In the 1950s, working with Donald Hebb (a former student of Lashley’s) at the Montreal Neurological Institute, Brenda Milner began studying some of neurosurgeon Wilder Penfield’s patients who had had different brain regions resected as part of treatment for epilepsy or other neurological disorders. She noted that a couple of patients with apparent bilateral hippocampal formation resections/damage had memory-related issues. After presenting these observations at a conference, Milner and Penfield were contacted by William Scoville, an American neurosurgeon who had performed similar surgeries and had noted memory deficits in some of his patients. Milner proceeded to examine some of Scoville’s patients"}, {"type": "citation_ref", "number": 42}, {"type": "text", "content": ", including patient H.M. (Henry Molaison), who had been having seizures since the age of 10, and severe episodes since the age of 16. By the age of 27, Molaison could no longer hold down a job and Scoville advised experimental bilateral hippocampal resection. Following the procedure, though his epilepsy was greatly reduced, Molaison could no longer form new memories (i.e., he suffered from anterograde amnesia). Milner carefully documented H.M.’s behaviors, finding that though he could not form new episodic memories, he was able to form new procedural memories (e.g., a mirror drawing task). Thus, not only was Milner able to identify the hippocampus as a critical region for the encoding of new memories"}, {"type": "citation_ref", "number": 42}, {"type": "text", "content": ", she was also able to establish that different types of memories—e.g., episodic (“I remember what happened where”) vs. procedural (“I know how to do it”)—were stored in different brain regions."}]}'::JSONB, 'Lashley’s conclusions on a lack of localization of function for memory processing didn’t hold for long. In the 1950s, working with Donald Hebb (a former student of Lashley’s) at the Montreal Neurological Institute, Brenda Milner began studying some of neurosurgeon Wilder Penfield’s patients who had had different brain regions resected as part of treatment for epilepsy or other neurological disorders. She noted that a couple of patients with apparent bilateral hippocampal formation resections/damage had memory-related issues. After presenting these observations at a conference, Milner and Penfi', 17, false, NULL, NULL, false, 0);

  -- Section: What''s the basic functional unit of the brain?
  INSERT INTO sections (module_id, title, slug, order_index)
  VALUES (v_module_id, 'What''s the basic functional unit of the brain?', 'basic-functional-unit', v_next_order)
  RETURNING id INTO v_section_id;
  v_next_order := v_next_order + 1;
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "While the debate about localization of function vs. equipotentiality was taking place at the gross anatomical level of what are now called brain regions, a similar debate occurred at the microscopic level at the scale of neurons. The debate centered on whether individual neurons were the fundamental functional units of the brain, or whether neurons were fused together into a giant syncytium."}]}'::JSONB, 'While the debate about localization of function vs. equipotentiality was taking place at the gross anatomical level of what are now called brain regions, a similar debate occurred at the microscopic level at the scale of neurons. The debate centered on whether individual neurons were the fundamental functional units of the brain, or whether neurons were fused together into a giant syncytium.', 0, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "By the middle of the 18th century, the gross anatomy of the brain had been described in reasonable detail. Following Thomas Willis, work by anatomists across Europe such as Gennari, Pourfour du Petit, Rolando, Vicq-D’Azyr, and Gratiolet, gave rise to a clear and detailed picture of the brain as a complex organ with multiple distinct anatomical regions. But what was the substance making up the organ of thought, memory, and emotions? Early explorations with small, hand-held homemade microscopes ("}, {"type": "figure_placeholder", "number": 12}, {"type": "text", "content": ") allowed the Dutch draper Antonie van Leeuwenhoek—who had started making his own microscopes to assess the quality of his fabrics—to examine countless biological specimens, including a cow optic nerve,"}, {"type": "citation_ref", "number": 43}, {"type": "text", "content": " which was the first nervous tissue to be seen at high magnification. Although without methods to enhance contrast, the optic nerve must have looked fairly nondescript to van Leeuwenhoek, it was sufficient for him to remark that the nerve was not composed of a hollow tube, as had been claimed by Alcmaeon over a thousand years earlier in Greece."}]}'::JSONB, 'By the middle of the 18th century, the gross anatomy of the brain had been described in reasonable detail. Following Thomas Willis, work by anatomists across Europe such as Gennari, Pourfour du Petit, Rolando, Vicq-D’Azyr, and Gratiolet, gave rise to a clear and detailed picture of the brain as a complex organ with multiple distinct anatomical regions. But what was the substance making up the organ of thought, memory, and emotions? Early explorations with small, hand-held homemade microscopes (Figure 12)) allowed the Dutch draper Antonie van Leeuwenhoek—who had started making his own microscop', 1, true, v_fig_12, 'auto', false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "In fact, looking at unstained brain tissue under a microscope, it is nearly impossible to visualize individual neurons, which are densely packed within tangles of ultra-thin dendritic and axonal processes. This limited initial progress in brain research after the development of the first microscopes. These obstacles, which also included difficulties in tissue handling (softness, degradation) and processing (sampling for microscopy), were gradually resolved during the 19th century. First, chemical solutions, from alcohol, to balsamic concoctions, to formaldehyde (the latter being still commonly used in neuroscience research) were increasingly employed to stop tissue degradation and harden fresh tissue samples, making brain matter easier to process for microscopy"}, {"type": "citation_ref", "number": 44}, {"type": "text", "content": ". Second, the development of a precise instrument for tissue cutting, the microtome, allowed for consistent sectioning of brain tissue that could then be mounted on glass slides"}, {"type": "citation_ref", "number": 45}, {"type": "citation_ref", "number": 46}, {"type": "text", "content": ". Third, various pigments and dyes, such as carmine or cresyl violet, were found to be efficient contrasting agents, revealing for the first time the brain’s myriad building blocks"}, {"type": "citation_ref", "number": 47}, {"type": "text", "content": ". Lastly, refinements in compound microscopes, initially invented by Robert Hooke in the mid-17th century, permitted observations of brain tissue with increasing clarity."}]}'::JSONB, 'In fact, looking at unstained brain tissue under a microscope, it is nearly impossible to visualize individual neurons, which are densely packed within tangles of ultra-thin dendritic and axonal processes. This limited initial progress in brain research after the development of the first microscopes. These obstacles, which also included difficulties in tissue handling (softness, degradation) and processing (sampling for microscopy), were gradually resolved during the 19th century. First, chemical solutions, from alcohol, to balsamic concoctions, to formaldehyde (the latter being still commonly', 2, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Jan Evangelista Purkyně (aka Purkinje) was one of the first to take advantage of these experimental conditions and described cerebellar cortex as containing large and tightly packed globular structures from which emerged short extensions. These would go on to be named Purkyně neurons"}, {"type": "citation_ref", "number": 48}, {"type": "text", "content": ". It remained unclear, though, whether globules—a term first used by Gabriel Valentin, one of Purkyně’s students—and nerve fibers were connected in any way. Others, such as Robert Remak and Otto Deiters, began using other staining approaches to visualize fibers in brain and spinal cord sections. A posthumous publication from Deiters in 1865 revealed that there were in fact two types of fibers, the axis cylinder (axon) and protoplasmic processes (dendrites), that extended from what looked like cell bodies"}, {"type": "citation_ref", "number": 49}, {"type": "text", "content": " ("}, {"type": "figure_placeholder", "number": 13}, {"type": "text", "content": "). However, Deiters hypothesized that these processes were fused to those of other “cells.” The idea that neuronal processes fused (or anastomosed) was formalized by German anatomist Joseph von Gerlach in 1871 when he proposed that the brain is built from specialized cells with extended fibers that fused with one another, forming a giant nerve net or syncytium"}, {"type": "citation_ref", "number": 50}, {"type": "text", "content": ". Various configurations were proposed for this syncytium: dendrites fusing with other dendrites, axons with other axons, and dendrites with axons. The reticular theory was widely accepted by biologists, even if it largely contradicted cell theory which had been formalized in 1839 by German anatomists Schwann, for animals, and Schleiden, for plants. Cell theory stated that all living organisms are made up of individual cells"}, {"type": "citation_ref", "number": 51}, {"type": "text", "content": ", but it seemed logical to consider that the brain, capable of exceptional functions, should present an exceptional structure not dependent on individual cells doing individual things. It was natural to think that the brain, which required lightning-fast information flow across and between its various regions, could be organized as a giant net of “cells.”"}]}'::JSONB, 'Jan Evangelista Purkyně (aka Purkinje) was one of the first to take advantage of these experimental conditions and described cerebellar cortex as containing large and tightly packed globular structures from which emerged short extensions. These would go on to be named Purkyně neurons. It remained unclear, though, whether globules—a term first used by Gabriel Valentin, one of Purkyně’s students—and nerve fibers were connected in any way. Others, such as Robert Remak and Otto Deiters, began using other staining approaches to visualize fibers in brain and spinal cord sections. A posthumous public', 3, true, v_fig_13, 'auto', false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "A breakthrough came in 1873 with the staining protocol developed by the Italian physician and pathologist Camillo Golgi"}, {"type": "citation_ref", "number": 52}, {"type": "text", "content": ". This staining, which he called the “black reaction” (<em>la reazione nera</em>) involved staining nervous tissue with silver, which allowed for the unprecedented visualization of individual cells in the brain. The main advantage of this staining method, which is still used by some researchers today, is that random cells in nervous tissue are very darkly stained in their entirety. Using this approach, Golgi produced elegant and highly detailed descriptions of nervous circuitries observed in various regions of the brain. For example, his rendering of olfactory bulb neurons revealed a complex arrangement of cells, layers and structures ("}, {"type": "figure_placeholder", "number": 14}, {"type": "text", "content": ")."}]}'::JSONB, 'A breakthrough came in 1873 with the staining protocol developed by the Italian physician and pathologist Camillo Golgi. This staining, which he called the “black reaction” (la reazione nera) involved staining nervous tissue with silver, which allowed for the unprecedented visualization of individual cells in the brain. The main advantage of this staining method, which is still used by some researchers today, is that random cells in nervous tissue are very darkly stained in their entirety. Using this approach, Golgi produced elegant and highly detailed descriptions of nervous circuitries obser', 4, true, v_fig_14, 'auto', false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Despite these advancements, Golgi’s staining method still tended to label many nearby neurons, making it difficult to resolve the processes belonging to individual neurons, and leading Golgi to put his support behind the syncytial enthusiasts (but see also"}, {"type": "citation_ref", "number": 53}, {"type": "text", "content": " for another perspective on Golgi’s syncytial leanings)."}]}'::JSONB, 'Despite these advancements, Golgi’s staining method still tended to label many nearby neurons, making it difficult to resolve the processes belonging to individual neurons, and leading Golgi to put his support behind the syncytial enthusiasts (but see also for another perspective on Golgi’s syncytial leanings).', 5, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Then, one day in 1887, while visiting his colleague Luis Simarro in Madrid, Spanish physician and anatomist Santiago Ramón y Cajal first came across tissue stained with Golgi’s reaction"}, {"type": "citation_ref", "number": 54}, {"type": "text", "content": ". One glance at the sharply contrasted cells convinced him that this was the method best suited for pursuing histological investigations of the nervous system, and he quickly threw himself into this endeavour. The originality of Ramón y Cajal’s approach was that he studied developing nervous tissue—the ontogenetic approach"}, {"type": "citation_ref", "number": 55}, {"type": "text", "content": ". The advantages of studying the immature nervous system were twofold: first, it is mostly unmyelinated, allowing for better staining; second, it contains growing elements which provided insights into how neurons connect with one another. By following the fate of processes growing from cell bodies across different points in development, Ramón y Cajal was the first to describe the growth cone ("}, {"type": "figure_placeholder", "number": 15}, {"type": "text", "content": "), the leading process of developing axons"}, {"type": "citation_ref", "number": 55}, {"type": "text", "content": ", and he concluded that such processes terminate in close apposition to other structures (cell bodies or processes) but never fuse with them. This close apposition was later called a synapse (from the Greek “to clasp”) by Charles Sherrington in 1897."}]}'::JSONB, 'Then, one day in 1887, while visiting his colleague Luis Simarro in Madrid, Spanish physician and anatomist Santiago Ramón y Cajal first came across tissue stained with Golgi’s reaction. One glance at the sharply contrasted cells convinced him that this was the method best suited for pursuing histological investigations of the nervous system, and he quickly threw himself into this endeavour. The originality of Ramón y Cajal’s approach was that he studied developing nervous tissue—the ontogenetic approach. The advantages of studying the immature nervous system were twofold: first, it is mostly ', 6, true, v_fig_15, 'auto', false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Ramón y Cajal’s demonstration that nerve cells do not form a syncytium but remain as individual units meant that the brain conformed to cell theory. Ramón y Cajal made many more crucial observations, and his remarkable power of deduction allowed him to identify the flow of information within cells (the law of dynamic polarization; from dendrites to cell body to axon) and circuits (e.g., see the arrows in "}, {"type": "figure_placeholder", "number": 16}, {"type": "text", "content": "). These observations and interpretations became known as the Neuron Doctrine, which was first laid out in 1891 by Heinrich von Waldeyer-Hartz, who coined the term <em>neuron</em>"}, {"type": "citation_ref", "number": 56}, {"type": "text", "content": "."}]}'::JSONB, 'Ramón y Cajal’s demonstration that nerve cells do not form a syncytium but remain as individual units meant that the brain conformed to cell theory. Ramón y Cajal made many more crucial observations, and his remarkable power of deduction allowed him to identify the flow of information within cells (the law of dynamic polarization; from dendrites to cell body to axon) and circuits (e.g., see the arrows in (Figure 16)). These observations and interpretations became known as the Neuron Doctrine, which was first laid out in 1891 by Heinrich von Waldeyer-Hartz, who coined the term neuron.', 7, true, v_fig_16, 'auto', false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Despite being highly influential and rapidly adopted by the field, the Neuron Doctrine was never accepted by Camillo Golgi, who maintained that the brain could not function holistically by relying on the activity of individual cells. When Ramón y Cajal and Golgi shared the 1906 Nobel Prize in Medicine or Physiology, they gave lectures that outlined their opposing viewpoints. Cajal’s lecture was titled <em>The structure and connections of neurons</em>"}, {"type": "citation_ref", "number": 57}, {"type": "text", "content": " and Golgi followed with a lecture titled <em>The Neuron Doctrine: theory and facts</em>"}, {"type": "citation_ref", "number": 58}, {"type": "text", "content": ". This controversial take by the Italian scientist surprised the Spaniard and frustrated many in the audience. In his memoir <em>Recollections of my life</em>"}, {"type": "citation_ref", "number": 59}, {"type": "text", "content": ", Cajal described the scene as follows:"}]}'::JSONB, 'Despite being highly influential and rapidly adopted by the field, the Neuron Doctrine was never accepted by Camillo Golgi, who maintained that the brain could not function holistically by relying on the activity of individual cells. When Ramón y Cajal and Golgi shared the 1906 Nobel Prize in Medicine or Physiology, they gave lectures that outlined their opposing viewpoints. Cajal’s lecture was titled The structure and connections of neurons and Golgi followed with a lecture titled The Neuron Doctrine: theory and facts. This controversial take by the Italian scientist surprised the Spaniard an', 8, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "blockquote", "content": "“The noble and most discrete Retzius was in consternation; Holmgren, Henschen, and all the Swedish neurologists and histologists contemplated the speaker with stupefaction. And I was trembling with impatience as I saw that the most elementary respect for the conventions prevented me from giving an opportune and categorical correction to so many odious errors and so many deliberate omissions.”"}]}'::JSONB, '', 9, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Despite his contrarian view, Golgi’s contributions to biology were innumerable. In addition to the staining method he invented, he and his students and staff at the University of Pavia ("}, {"type": "figure_placeholder", "number": 17}, {"type": "text", "content": ") made several remarkable observations, describing, for example, the muscle-associated spindle essential for proprioception (Golgi tendon organ)"}, {"type": "citation_ref", "number": 60}, {"type": "text", "content": " and the Golgi apparatus"}, {"type": "citation_ref", "number": 61}, {"type": "text", "content": "."}]}'::JSONB, 'Despite his contrarian view, Golgi’s contributions to biology were innumerable. In addition to the staining method he invented, he and his students and staff at the University of Pavia (Figure 17)) made several remarkable observations, describing, for example, the muscle-associated spindle essential for proprioception (Golgi tendon organ) and the Golgi apparatus.', 10, true, v_fig_17, 'auto', false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Unfortunately for Golgi and Ramón y Cajal, the diffraction limit is approximately 0.2 μm, meaning that with their light microscopes they were unable to resolve the junctions that exist at the contact points between one neuron’s axon and another neuron’s dendrites. It wasn’t until the 1950s and the development of electron microscopy that sufficient magnification power was obtained to visualize gaps of 20-30 nm that are typical of central nervous system synapses. Sanford Palay and colleagues were the first to describe a protocol for the rapid fixation and staining of membranes that permitted visualization of the ultrastructure of nervous tissue. The images they obtained showed the synaptic structure for the first time: the presynaptic terminal, filled with vesicles and containing mitochondria, and its terminal membrane closely apposed to the postsynaptic element (a postsynaptic dendrite or cell body; "}, {"type": "figure_placeholder", "number": 18}, {"type": "text", "content": "). In the first major paper on the topic in 1956, Palay concluded: “The absence of protoplasmic continuity across the contact surface between the two members of the synaptic apparatus is impressive confirmation of the neuron doctrine enunciated and **defended by Ramón y Cajal during the early part of this century.”"}, {"type": "citation_ref", "number": 62}, {"type": "text", "content": " Such chemical synapses have been found over and over again throughout the nervous system, and make up the major mechanism used by neurons to communicate with one another."}]}'::JSONB, 'Unfortunately for Golgi and Ramón y Cajal, the diffraction limit is approximately 0.2 μm, meaning that with their light microscopes they were unable to resolve the junctions that exist at the contact points between one neuron’s axon and another neuron’s dendrites. It wasn’t until the 1950s and the development of electron microscopy that sufficient magnification power was obtained to visualize gaps of 20-30 nm that are typical of central nervous system synapses. Sanford Palay and colleagues were the first to describe a protocol for the rapid fixation and staining of membranes that permitted vis', 11, true, v_fig_18, 'auto', false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "<em>The Neuron Doctrine revisited</em>: The remarkable progress achieved in neuroscience since the discovery of chemical synapses has revealed the limitations of the Neuron Doctrine. For example, neurons are far from being the only cells in the brain. Although estimates vary and important regional differences have been reported, it seems there are as many glial cells as neurons in the human brain"}, {"type": "citation_ref", "number": 63}, {"type": "text", "content": ". Furthermore, the discovery of gap junctions in the nervous system (outlined in more detail below) has revealed that individual neurons and glial cells can take part in large gap junction coupled networks, an arrangement reminiscent of the reticular theory"}, {"type": "citation_ref", "number": 64}, {"type": "text", "content": ". Finally, in some organisms, neurons themselves appear to be organized predominantly in a syncytial manner"}, {"type": "citation_ref", "number": 65}, {"type": "text", "content": "."}]}'::JSONB, 'The Neuron Doctrine revisited: The remarkable progress achieved in neuroscience since the discovery of chemical synapses has revealed the limitations of the Neuron Doctrine. For example, neurons are far from being the only cells in the brain. Although estimates vary and important regional differences have been reported, it seems there are as many glial cells as neurons in the human brain. Furthermore, the discovery of gap junctions in the nervous system (outlined in more detail below) has revealed that individual neurons and glial cells can take part in large gap junction coupled networks, an ', 12, false, NULL, NULL, false, 0);

  -- Section: How do neurons communicate?
  INSERT INTO sections (module_id, title, slug, order_index)
  VALUES (v_module_id, 'How do neurons communicate?', 'how-neurons-communicate', v_next_order)
  RETURNING id INTO v_section_id;
  v_next_order := v_next_order + 1;
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Once the Neuron Doctrine became the established view of how neurons interconnect, in the absence of experimental evidence outlining the actual nature of synapses, the debate began as to how neurons communicate with one another. The debate ended up focusing on whether neurons communicate through electrical mechanisms or whether neurons release chemicals that are sensed by other neurons."}]}'::JSONB, 'Once the Neuron Doctrine became the established view of how neurons interconnect, in the absence of experimental evidence outlining the actual nature of synapses, the debate began as to how neurons communicate with one another. The debate ended up focusing on whether neurons communicate through electrical mechanisms or whether neurons release chemicals that are sensed by other neurons.', 0, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Intrinsic animal electricity was first demonstrated in the nervous system in the 1780s by Luigi Galvani in his experiments conducted using the frog leg preparation ("}, {"type": "figure_placeholder", "number": 19}, {"type": "text", "content": "). Electricity represented a natural force behind nerve function that replaced the notion of animal spirits flowing between the brain and the rest of the body. This discovery revolutionized biology and gave rise, early in the 19th century, to the field of electrophysiology"}, {"type": "citation_ref", "number": 66}, {"type": "text", "content": ". Nonetheless, the characterization of fundamental phenomena such as membrane hyperpolarization and depolarization, axon potentials, and the identification of the implicated ions and membrane channels took more than a century to achieve because this work increasingly required sensitive instruments and appropriate preparations to amplify and record small and rapid electrical events"}, {"type": "citation_ref", "number": 67}, {"type": "text", "content": "."}]}'::JSONB, 'Intrinsic animal electricity was first demonstrated in the nervous system in the 1780s by Luigi Galvani in his experiments conducted using the frog leg preparation (Figure 19)). Electricity represented a natural force behind nerve function that replaced the notion of animal spirits flowing between the brain and the rest of the body. This discovery revolutionized biology and gave rise, early in the 19th century, to the field of electrophysiology. Nonetheless, the characterization of fundamental phenomena such as membrane hyperpolarization and depolarization, axon potentials, and the identificat', 1, true, v_fig_19, 'auto', false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Yet major issues could not be easily accounted for by electrical neuronal communication. For instance, how could electrical currents lead to inhibition in the nervous system? By the 1920s, several scientists had arrived at the conclusion that endogenous molecules were likely used by peripheral nerves. Pharmacological experiments had characterized the effects of many compounds on peripheral organs. For example, Thomas Renton Elliott published a paper in 1905 describing the effects of adrenal gland extracts on the bladder"}, {"type": "citation_ref", "number": 68}, {"type": "text", "content": ". The relaxant effect of the extract was like that observed following stimulation of the sympathetic nervous system, which reinforced the notion that endogenous molecules could play a role at the synapse. But direct experimental evidence was lacking. This eventually gave rise to the <em>Soups vs. Sparks</em> debate"}, {"type": "citation_ref", "number": 69}, {"type": "text", "content": ", with some being convinced that chemical components (soups) must mediate neurotransmission, while others firmly believed that electricity (sparks) was the only medium that could reasonably convey fast messages between neurons. This debate would be settled, in part, by studying the heart."}]}'::JSONB, 'Yet major issues could not be easily accounted for by electrical neuronal communication. For instance, how could electrical currents lead to inhibition in the nervous system? By the 1920s, several scientists had arrived at the conclusion that endogenous molecules were likely used by peripheral nerves. Pharmacological experiments had characterized the effects of many compounds on peripheral organs. For example, Thomas Renton Elliott published a paper in 1905 describing the effects of adrenal gland extracts on the bladder. The relaxant effect of the extract was like that observed following stimu', 2, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "The Austrian pharmacologist Otto Loewi (1873-1961) had long been thinking about the Soups vs. Sparks debate when he returned to his alma mater to become Chair of the Department of Pharmacology at the University of Graz"}, {"type": "citation_ref", "number": 70}, {"type": "text", "content": ". Loewi was convinced that chemical mediators were responsible for the parasympathetic slowing down and sympathetic acceleration of the heartbeat. The heart has long been a model system of choice for studying the nervous system and identifying substances, usually derived from plants or animals, that would mimic, modulate or block the effects of nerve activation on heart rate. But it wasn’t clear where or how these drugs acted. The concept of a receptor substance was proposed by Charles Langley in 1905, defined as a chemical substance acting at the synapse, meaning that nervous system function could be modulated by application of certain drugs"}, {"type": "citation_ref", "number": 71}, {"type": "text", "content": ". For example, the application of nicotine or curare at the neuromuscular junction was known to contract or paralyze muscles, respectively, by interacting with the receptor substance on the postsynaptic muscle cell. This concept, however, was only framed to account for the pharmacological actions of exogenous drugs and did not account for endogenous molecules. Loewi, who had long been thinking about an experimental approach that would confirm the implication of endogenous mediators of synaptic transmission, found the solution in 1920 thanks to perhaps the most famous dreams in the history of science:"}]}'::JSONB, 'The Austrian pharmacologist Otto Loewi (1873-1961) had long been thinking about the Soups vs. Sparks debate when he returned to his alma mater to become Chair of the Department of Pharmacology at the University of Graz. Loewi was convinced that chemical mediators were responsible for the parasympathetic slowing down and sympathetic acceleration of the heartbeat. The heart has long been a model system of choice for studying the nervous system and identifying substances, usually derived from plants or animals, that would mimic, modulate or block the effects of nerve activation on heart rate. But', 3, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "blockquote", "content": "“The night before Easter Sunday I awoke, turned on the light and jotted down a few notes on a tiny slip of thin paper. Then I fell asleep again. It occurred to me at 6.00 o’clock in the morning that during the night I had written down something important, but I was unable to decipher the scrawl. The next night, at 3.00 o’clock, the idea returned. It was the design of an experiment to determine whether or not the hypothesis of chemical transmission that I had uttered 17 years ago was correct. I got up immediately, went to the laboratory, and performed a simple experiment on a frog heart according to the nocturnal design<em>.</em>”<sup><em>72</em></sup>"}]}'::JSONB, '', 4, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "The experiment he dashed off to perform in the middle of the night was simple and elegant. He isolated a frog heart and stimulated the cardiac branch of the vagus nerve (parasympathetic system) which, as expected, slowed down the heartbeat. Then, he collected the solution in which the heart was bathed and applied it to a second (denervated) heart, which began beating more slowly when exposed to the solution"}, {"type": "citation_ref", "number": 73}, {"type": "text", "content": " ("}, {"type": "figure_placeholder", "number": 20}, {"type": "text", "content": "). This demonstrated that the vagus nerve, when stimulated, led to release of a molecule that impacted heart rate. Loewi named this molecule <em>Vagusstoff</em>. Later, he carried out a similar experiment, but this time he stimulated the accelerator nerve (sympathetic system), which resulted in both hearts displaying an increased heartbeat. He called the excitatory compound <em>Acceleransstoff</em>. Otto Loewi had demonstrated chemical neurotransmission and explained how nerve stimulation could lead to both excitation and inhibition"}, {"type": "citation_ref", "number": 70}, {"type": "text", "content": ". But what was the chemical nature of these compounds?"}]}'::JSONB, 'The experiment he dashed off to perform in the middle of the night was simple and elegant. He isolated a frog heart and stimulated the cardiac branch of the vagus nerve (parasympathetic system) which, as expected, slowed down the heartbeat. Then, he collected the solution in which the heart was bathed and applied it to a second (denervated) heart, which began beating more slowly when exposed to the solution (Figure 20)). This demonstrated that the vagus nerve, when stimulated, led to release of a molecule that impacted heart rate. Loewi named this molecule Vagusstoff. Later, he carried out a s', 5, true, v_fig_20, 'auto', false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Henry Dale, who had trained with Langley at Cambridge, demonstrated with his colleagues that <em>Vagusstoff</em> was in fact acetylcholine, making it the first neurotransmitter to be identified"}, {"type": "citation_ref", "number": 74}, {"type": "text", "content": ". His research was aimed at identifying compounds that could be used in the clinic, and he had been focusing before World War I on the physiological properties of ergot, a parasitic fungus of rye. Ergot contains multiple psychoactive compounds, and Dale observed in 1913 that injecting an animal with ergot extract slowed its heart rate. A year later, with his colleague Arthur Ewins, Dale found that this substance was identical, in its chemical properties and physiological effects, to acetylcholine, a molecule that had been synthesized in 1906 by pharmacologist Reid Hunt and found by Hunt to potently decrease blood pressure"}, {"type": "citation_ref", "number": 75}, {"type": "text", "content": ". It was now essential to demonstrate that acetylcholine was also found in animal tissues. This is exactly what Henry Dale and Harold Dudley achieved using over 30 kilograms of horse spleens obtained from slaughterhouses, as described in their 1929 paper <em>The presence of histamine and acetylcholine in the spleen of the ox and the horse</em>"}, {"type": "citation_ref", "number": 76}, {"type": "text", "content": ". In 1936, the Nobel Prize in Medicine or Physiology was jointly attributed to Loewi and Dale, “for their discoveries relating to chemical transmission of nerve impulses”. Dale, knowing that the brain also contained acetylcholine, concluded his Nobel lecture by discussing the possibility that chemical neurotransmission might also occur in the CNS:"}]}'::JSONB, 'Henry Dale, who had trained with Langley at Cambridge, demonstrated with his colleagues that Vagusstoff was in fact acetylcholine, making it the first neurotransmitter to be identified. His research was aimed at identifying compounds that could be used in the clinic, and he had been focusing before World War I on the physiological properties of ergot, a parasitic fungus of rye. Ergot contains multiple psychoactive compounds, and Dale observed in 1913 that injecting an animal with ergot extract slowed its heart rate. A year later, with his colleague Arthur Ewins, Dale found that this substance ', 6, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "blockquote", "content": "“Hitherto the evidence concerning a chemical transmission in the central nervous system, of the type which we have found prevailing at all peripheral synapses, is scattered and insufficiently uniform in its indications. The basal ganglia of the brain are peculiarly rich in acetylcholine, the presence of which must presumably have some significance; and suggestive effects of eserine and of acetylcholine, injected into the ventricles of the brain, have been described. I take the view, however, that we need a much larger array of well authenticated facts, before we begin to theorize. It is here, especially, that we need to proceed with caution; if the principle of chemical transmission is ultimately to find a further extension to the interneuronal transmission in the brain itself, it is by patient testing of the groundwork of experimental fact, at each new step, that a safe and steady advance will be achieved. The possible importance of such an extension, even for practical medicine and therapeutics, could hardly be overestimated.<sup>77</sup>”"}]}'::JSONB, '', 7, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "But seeing as autonomic innervations can operate on relatively slow timescales, there was resistance to the idea that chemical synaptic transmission also occurred in the CNS and at the neuromuscular junction at skeletal muscles, where fast processing is needed. The leading opponent to chemical neurotransmission in the CNS was the Australian neurophysiologist John Eccles"}, {"type": "citation_ref", "number": 78}, {"type": "text", "content": ", who had animated public debates with Dale and others. Soon, researchers including Bernard Katz"}, {"type": "citation_ref", "number": 79}, {"type": "text", "content": " would provide experimental evidence in support of acetylcholine being released by pre-ganglionic neurons as well as by motoneurons at the neuromuscular junction. Eventually Eccles had to recognize that chemical neurotransmission was a mechanism used throughout the peripheral nervous system"}, {"type": "citation_ref", "number": 80}, {"type": "text", "content": ". The CNS, however, was another story, and Eccles thought of a clever hypothesis that would disprove, once and for all, the notion of chemical neurotransmission in the brain and spinal cord. This hypothesis was based on the stretch reflex circuitry in the spinal cord. Eccle’s hypothesis concerned the role played by an interneuron (a Golgi cell) inhibiting the contraction of the antagonist muscle. Eccles hypothesized that this interneuron dampened the excitation received from a sensory neuron via an ephaptic mechanism ("}, {"type": "figure_placeholder", "number": 21}, {"type": "text", "content": "). If Eccles was correct, stimulating the part of the circuit known to inhibit the motor pathway would drive a small depolarization in the motor neuron of interest (i.e., ****in Eccles’ model ("}, {"type": "figure_placeholder", "number": 21}, {"type": "text", "content": "), activation of the inhibitory pathway (neuron I), would drive subthreshold activation of interneuron G, which would result in an electric field effect that would slightly depolarize neuron M but also dampen its ability to get activated by neuron E). If, on the other hand, interneuron G released an inhibitory neurotransmitter, a hyperpolarization would be detected in the motor neuron"}, {"type": "citation_ref", "number": 81}, {"type": "text", "content": ". To his great surprise, Eccles recorded a hyperpolarization. After repeating the experiment several times and obtaining the same result"}, {"type": "citation_ref", "number": 82}, {"type": "text", "content": ", Eccles had no choice but to accept his own demonstration that a chemical mediator had been released by a neuron in the CNS. In 1963, a quarter century after Dale and Loewi, John Eccles was awarded the Nobel Prize in Medicine or Physiology, together with Alan Hodgkin and Andrew Huxley—who showed that action potentials arise from an intricate interplay between voltage gated Na<sup>+</sup> and K<sup>+</sup> channels"}, {"type": "citation_ref", "number": 83}, {"type": "text", "content": "— “for their discoveries concerning the ionic mechanisms involved in excitation and inhibition in the nerve cell membrane.” This breakthrough established that nerve cells, both peripherally and centrally, communicate via electrical and chemical methods. Since then, more than 100 neurotransmitters have been identified and localized in the nervous system, further highlighting the complexity of the nervous system."}]}'::JSONB, 'But seeing as autonomic innervations can operate on relatively slow timescales, there was resistance to the idea that chemical synaptic transmission also occurred in the CNS and at the neuromuscular junction at skeletal muscles, where fast processing is needed. The leading opponent to chemical neurotransmission in the CNS was the Australian neurophysiologist John Eccles, who had animated public debates with Dale and others. Soon, researchers including Bernard Katz would provide experimental evidence in support of acetylcholine being released by pre-ganglionic neurons as well as by motoneurons ', 8, true, v_fig_21, 'auto', false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "That being said, while electron microscope data provided photographic evidence of chemical synapses in 1956, by 1959 data was emerging that supported the existence of electrical synapses"}, {"type": "citation_ref", "number": 84}, {"type": "text", "content": ". Since then, electrical synapses have been shown to be present across the CNS, and roles have been established for electrical synapses, which arise via gap junctions, often involving synchronizing neuronal activity. Thus, soups and sparks work together in the brain"}, {"type": "citation_ref", "number": 85}, {"type": "citation_ref", "number": 86}, {"type": "text", "content": "."}]}'::JSONB, 'That being said, while electron microscope data provided photographic evidence of chemical synapses in 1956, by 1959 data was emerging that supported the existence of electrical synapses. Since then, electrical synapses have been shown to be present across the CNS, and roles have been established for electrical synapses, which arise via gap junctions, often involving synchronizing neuronal activity. Thus, soups and sparks work together in the brain.', 9, false, NULL, NULL, false, 0);

  -- Section: Closing words
  INSERT INTO sections (module_id, title, slug, order_index)
  VALUES (v_module_id, 'Closing words', 'closing-words', v_next_order)
  RETURNING id INTO v_section_id;
  v_next_order := v_next_order + 1;
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "As you may appreciate by this point, the history of neuroscience is littered with debates in which, to at least some extent, people on each side of the dispute were often both partly right and partly wrong. Furthermore, topics that once seemed settled can become highly contested when additional findings come to light. Nonetheless, with a combination of critical thinking and clever experimentation, over time we can slowly approach a correct understanding of how the brain works. Or, as the physiologist and visual scientist Selig Hecht once wrote, “If one can succeed in bringing a number of scattered phenomena into orderly arrangement, one decreases by so much the welter of unrelated facts that constitutes the present literature."}, {"type": "citation_ref", "number": 87}, {"type": "text", "content": "”"}]}'::JSONB, 'As you may appreciate by this point, the history of neuroscience is littered with debates in which, to at least some extent, people on each side of the dispute were often both partly right and partly wrong. Furthermore, topics that once seemed settled can become highly contested when additional findings come to light. Nonetheless, with a combination of critical thinking and clever experimentation, over time we can slowly approach a correct understanding of how the brain works. Or, as the physiologist and visual scientist Selig Hecht once wrote, “If one can succeed in bringing a number of scatt', 0, false, NULL, NULL, false, 0);

  -- Section: Separating mind from body: Descartes and dualism
  INSERT INTO sections (module_id, title, slug, order_index)
  VALUES (v_module_id, 'Separating mind from body: Descartes and dualism', 'box-descartes', v_next_order)
  RETURNING id INTO v_section_id;
  v_next_order := v_next_order + 1;
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Descartes is often credited with popularizing the idea of dualism"}, {"type": "citation_ref", "number": 88}, {"type": "text", "content": "—the idea that most of our bodily functions and capabilities arise from our corporeal being, but that our mind, or soul, arises in an ethereal, perhaps spiritual, manner. Even hundreds of years after Descartes’ death, such ideas continue to have traction, particularly in conversations surrounding the basis of consciousness"}, {"type": "citation_ref", "number": 89}, {"type": "text", "content": ". Somewhat ironically, in death Descartes also came to embody the idea of separation of mind and body."}]}'::JSONB, 'Descartes is often credited with popularizing the idea of dualism —the idea that most of our bodily functions and capabilities arise from our corporeal being, but that our mind, or soul, arises in an ethereal, perhaps spiritual, manner. Even hundreds of years after Descartes’ death, such ideas continue to have traction, particularly in conversations surrounding the basis of consciousness. Somewhat ironically, in death Descartes also came to embody the idea of separation of mind and body.', 0, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "In 1649, Descartes was invited by Queen Christina of Sweden to visit and serve as her tutor. He went to Sweden but died soon afterward of pneumonia. He was buried in a small Catholic church in the outskirts of otherwise Protestant Stockholm. Several years later, during a period of patriotic fervor, the French decided to bring back their great thinker. A team was sent to bring Descartes’ body back home. However, once back in France, something was wrong with Descartes’ remains. His skull was missing. So was his right index finger."}]}'::JSONB, 'In 1649, Descartes was invited by Queen Christina of Sweden to visit and serve as her tutor. He went to Sweden but died soon afterward of pneumonia. He was buried in a small Catholic church in the outskirts of otherwise Protestant Stockholm. Several years later, during a period of patriotic fervor, the French decided to bring back their great thinker. A team was sent to bring Descartes’ body back home. However, once back in France, something was wrong with Descartes’ remains. His skull was missing. So was his right index finger.', 1, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "It seems the French ambassador to Sweden kept the finger as a souvenir"}, {"type": "citation_ref", "number": 90}, {"type": "text", "content": ". Historian Stanley Finger suggests the head was removed because the French sent a casket that was too short"}, {"type": "citation_ref", "number": 8}, {"type": "text", "content": ". Whatever the reason, Descartes’ skull was missing until 1821, when Berzalius, a Swedish chemist, noticed an estate sale in a Stockholm newspaper that included “the skull of the famous Cartesius"}, {"type": "citation_ref", "number": 91}, {"type": "text", "content": "” (Cartesius being the Latinized form of Descartes). Berzilius enquired about the skull but found it had already been sold. So, he tracked down the new owner and bought it off him"}, {"type": "citation_ref", "number": 91}, {"type": "text", "content": ". When Berzalius acquired the skull, it was missing the jaw and had text written all over it in ink, including the following poem (translated from Latin):"}]}'::JSONB, 'It seems the French ambassador to Sweden kept the finger as a souvenir. Historian Stanley Finger suggests the head was removed because the French sent a casket that was too short. Whatever the reason, Descartes’ skull was missing until 1821, when Berzalius, a Swedish chemist, noticed an estate sale in a Stockholm newspaper that included “the skull of the famous Cartesius ” (Cartesius being the Latinized form of Descartes). Berzilius enquired about the skull but found it had already been sold. So, he tracked down the new owner and bought it off him. When Berzalius acquired the skull, it was mis', 2, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "“This small skull once belonged to the great Cartesius,"}]}'::JSONB, '“This small skull once belonged to the great Cartesius,', 3, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "The rest of his remains are hidden far away in the land of France;"}]}'::JSONB, 'The rest of his remains are hidden far away in the land of France;', 4, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "But all around the circle of the globe his genius is praised,"}]}'::JSONB, 'But all around the circle of the globe his genius is praised,', 5, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "And his spirit still rejoices in the sphere of heaven.”"}, {"type": "citation_ref", "number": 91}]}'::JSONB, 'And his spirit still rejoices in the sphere of heaven.”', 6, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Berzilius gave the skull to the French Académie de Sciences. The skull now resides in the Musée de l’homme in Paris ("}, {"type": "figure_placeholder", "number": "A"}, {"type": "text", "content": "), though there is controversy regarding whether or not it is truly Descartes’ skull, as a museum in Lund, Sweden, also displays a portion of what they claim is the true “Skull of the Philosopher Descartes.” ("}, {"type": "figure_placeholder", "number": "B"}, {"type": "text", "content": ")."}]}'::JSONB, 'Berzilius gave the skull to the French Académie de Sciences. The skull now resides in the Musée de l’homme in Paris (Figure A)), though there is controversy regarding whether or not it is truly Descartes’ skull, as a museum in Lund, Sweden, also displays a portion of what they claim is the true “Skull of the Philosopher Descartes.” (Figure B)).', 7, true, v_fig_a, 'auto', false, 0);

  -- Section: Failures in comparative neuroanatomy: The rete mirabile and hippocampus minor
  INSERT INTO sections (module_id, title, slug, order_index)
  VALUES (v_module_id, 'Failures in comparative neuroanatomy: The rete mirabile and hippocampus minor', 'box-rete-mirabile', v_next_order)
  RETURNING id INTO v_section_id;
  v_next_order := v_next_order + 1;
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "hippocampus minor"}]}'::JSONB, 'hippocampus minor', 0, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "How does our brain generate the mind? In his book <em>Method of Treatment</em>, Galen writes: \"Concerning the psychic spirit [also known as animal spirits], we have clearly shown that the brain is its fount, so to speak, and that it is watered and nourished by inspiration and by the supply from the rete mirabile [also known as the retiform plexus]. Concerning the vital spirit, the demonstration has not been equally clear, yet it does not seem unlikely that it is contained in the heart and the arteries and that it too is chiefly nourished by the respiration and also the blood. And if there also is a natural spirit, this again should be contained in the liver and the veins.”"}, {"type": "citation_ref", "number": 92}, {"type": "text", "content": " The idea being that the nature of these spirits, or pneuma, would get elaborated from one organ to the next, and the complex structure of the rete mirabile—a complex vascular mesh at the base of the brain—would allow spirits the time to develop from the vital to the psychic kind"}, {"type": "citation_ref", "number": 93}, {"type": "text", "content": " ("}, {"type": "figure_placeholder", "number": "C"}, {"type": "text", "content": "). The only issue is that humans do not have a rete mirabile. But Galen did not have access to human tissue for dissection. He did have access to ungulates—hooved animals that possess a rete mirabile. He also mentioned that Herophilus previously described the rete mirabile, and Herophilus was thought to have dissected human tissue, so Galen may have assumed that Herophilus noted this structure in humans"}, {"type": "citation_ref", "number": 93}, {"type": "text", "content": ". Regardless the exact etiology of the mistake, this error of Galen’s would survive for over a thousand years, until Vesalius, in 1543 in <em>De humani corporis fabrica,</em> finally realized that humans do not have a rete mirabile (though it should be noted that Berengario da Carpi in Bologna had mentioned his inability to find the rete mirabile in humans a few year before Vesalius"}, {"type": "citation_ref", "number": 94}, {"type": "text", "content": "). Previously, in 1538, in <em>Tabulae Anatomicae Sex</em>, Vesalius had even drawn the rete mirabile on top of the carotid arteries, but had done it based on Galen’s authority. Five years later, he wrote, “I cannot sufficiently marvel at my own stupidity; I who have so labored in my love for Galen that I have never demonstrated the human head without that of a lamb or ox, to show in the latter what I could not see in the former, lest forsooth I should fail that universally familiar plexus. For in no way the carotics form a plexus reticularis [in man] as Galen alleges."}, {"type": "citation_ref", "number": 95}, {"type": "text", "content": "” Alas, this wasn’t the final death knell for the rete mirabile in man. Even Thomas Willis—who first described a related structure in humans, now known as the Circle of Willis, a little over a hundred years after the publication of <em>De humani corporis fabrica</em>—wrote that some people still believed the rete mirabile to occasionally be present in humans, and he conjectured that this likely coincided with “slender wit and unmoved disposition."}, {"type": "citation_ref", "number": 94}, {"type": "text", "content": "”"}]}'::JSONB, 'How does our brain generate the mind? In his book Method of Treatment, Galen writes: "Concerning the psychic spirit [also known as animal spirits], we have clearly shown that the brain is its fount, so to speak, and that it is watered and nourished by inspiration and by the supply from the rete mirabile [also known as the retiform plexus]. Concerning the vital spirit, the demonstration has not been equally clear, yet it does not seem unlikely that it is contained in the heart and the arteries and that it too is chiefly nourished by the respiration and also the blood. And if there also is a nat', 1, true, v_fig_c, 'auto', false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "In contrast to the example above where an anatomical structure present in non-humans was mistakenly assigned to humans, during the heated academic debates following the release of Darwin’s <em>On the</em> <em>Origins of Species</em>, the inverse situation arose: a controversy about whether a certain brain structure was specific to humans and thus differentiated us from the rest of the animal kingdom. The year was 1858 and Richard Owen, Hunterian professor at the Royal College of Surgeons and superintendent of the British Museum, published a paper claiming that three parts of brain anatomy clearly distinguished humans from other primates. It seems likely that he was aware that Darwin’s book was about to be published and he wanted to get in front of it with a win for the anti-evolution side. In contrast to Linnaeus, Owen went so far as to put humans in an order of the phylogenetic tree all by themselves"}, {"type": "citation_ref", "number": 96}, {"type": "text", "content": ". Owen’s claims were: 1) only in humans does the posterior part of the cerebrum (i.e., the caudal-most part of cortex) extend beyond and thus cover the cerebellum; 2) only humans have a posterior horn in their lateral ventricle; 3) only humans have a hippocampus minor (a structure now referred to as the calcar avis). The problem was that Owen—despite other important contributions to knowledge and the public dissemination of knowledge via his work at the British Museum—was wrong on each of these fronts. It seems that Owen largely based his conclusions on a belief that humans were superior to other animals, and a misreading (possibly purposefully so) of the scientific literature. Over the next years, “Darwin’s Bulldog” Thomas Huxley, then professor of General Natural History at the Government School of Mines pursued a single-minded take-down of Owen over these claims. Across several publications, Huxley and other like-minded scientists performed numerous dissections comparing human and non-human primate brains, outlining that each of Owen’s three claims were incorrect, and showing that the hippocampus minor was not unique to humans"}, {"type": "citation_ref", "number": 96}, {"type": "text", "content": " ("}, {"type": "figure_placeholder", "number": "D"}, {"type": "text", "content": "). Though Owen dug in his heels, so much evidence accumulated against his position in a short period of time that his scientific credibility quickly declined."}]}'::JSONB, 'In contrast to the example above where an anatomical structure present in non-humans was mistakenly assigned to humans, during the heated academic debates following the release of Darwin’s On the Origins of Species, the inverse situation arose: a controversy about whether a certain brain structure was specific to humans and thus differentiated us from the rest of the animal kingdom. The year was 1858 and Richard Owen, Hunterian professor at the Royal College of Surgeons and superintendent of the British Museum, published a paper claiming that three parts of brain anatomy clearly distinguished ', 2, true, v_fig_d, 'auto', false, 0);

  -- Section: The doctor with an icepick: A brief history of psychosurgeries
  INSERT INTO sections (module_id, title, slug, order_index)
  VALUES (v_module_id, 'The doctor with an icepick: A brief history of psychosurgeries', 'box-psychosurgery', v_next_order)
  RETURNING id INTO v_section_id;
  v_next_order := v_next_order + 1;
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "The first ‘psychosurgeries’ were performed between 1888 and 1891 by Dr. Gottlieb Burckhardt, a Swiss psychiatrist working in the small canton of Neuchâtel. Burckhardt was a localizationalist who believed that “psychic lives are built up of individual elements that are settled in the brain and are situated in different locations.” He also believed in the medical principle of <em>melius anceps remedium quam nullum</em> (better a dangerous remedy than nothing) over that of <em>premium non nocere</em> (first do no harm)"}, {"type": "citation_ref", "number": 97}, {"type": "text", "content": ". He selected six patients, two woman and four men, who suffered from what he considered to be severe and intractable schizophrenia. He resected small portions of brain matter—predominantly from cortical association areas to try to stop aberrant activity from propagating—in hopes of alleviating their symptoms ("}, {"type": "figure_placeholder", "number": "E"}, {"type": "text", "content": "). He resected several different brain areas from a couple of the patients, and advocated for additional surgeries for the others"}, {"type": "citation_ref", "number": 98}, {"type": "citation_ref", "number": 97}, {"type": "text", "content": ". Following his first psychosurgery, he wrote that the patient “had been changed from a dangerous and excited dement (schizophrenic) into a quiet one. The incessant flow of words is interrupted, she has become quiet. Her intelligence has not returned, but she has definitely not lost anything that she had before.” Of the six patients he treated, one died from the surgery, one drowned under suspicious circumstances soon after “recovering,” and the other four were apparently more docile"}, {"type": "citation_ref", "number": 97}, {"type": "text", "content": ". Burckhardt considered his work a modest success"}, {"type": "citation_ref", "number": 97}, {"type": "citation_ref", "number": 98}, {"type": "text", "content": ", but his psychosurgical work was not well-received by the medical community"}, {"type": "citation_ref", "number": 97}, {"type": "citation_ref", "number": 99}, {"type": "text", "content": "."}]}'::JSONB, 'The first ‘psychosurgeries’ were performed between 1888 and 1891 by Dr. Gottlieb Burckhardt, a Swiss psychiatrist working in the small canton of Neuchâtel. Burckhardt was a localizationalist who believed that “psychic lives are built up of individual elements that are settled in the brain and are situated in different locations.” He also believed in the medical principle of melius anceps remedium quam nullum (better a dangerous remedy than nothing) over that of premium non nocere (first do no harm). He selected six patients, two woman and four men, who suffered from what he considered to be se', 0, true, v_fig_e, 'auto', false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Psychosurgeries didn’t take off again until the mid-1930s when Portuguese neurologist Egas Moniz—who was shot once by a patient with schizophrenia"}, {"type": "citation_ref", "number": 99}, {"type": "text", "content": "—with help of various neurosurgeons, performed lesions in the frontal lobes of several patients"}, {"type": "citation_ref", "number": 100}, {"type": "text", "content": ". Inspired by a study showing that chimpanzees became less prone to being agitated following frontal lobe resections"}, {"type": "citation_ref", "number": 101}, {"type": "text", "content": ", Moniz sought to sever white matter tracts between the frontal lobes and the rest of the brain via a process he called leucotomy"}, {"type": "citation_ref", "number": 102}, {"type": "text", "content": ", as he felt the frontal lobes were the source of agitation in mentally ill patients. Moniz was quick to defend his procedure, which he said “might be called in question; the surgical intervention might be considered very audacious; but such arguments occupy a secondary position because it can be affirmed now that these operations are not prejudicial to either physical or psychic life of the patient, and also that recovery or improvement may be obtained frequently in this way."}, {"type": "citation_ref", "number": 102}, {"type": "text", "content": "” In his early cohort, Moniz claimed that his procedure improved the condition in over half the patients, with no long term negative impacts."}]}'::JSONB, 'Psychosurgeries didn’t take off again until the mid-1930s when Portuguese neurologist Egas Moniz—who was shot once by a patient with schizophrenia —with help of various neurosurgeons, performed lesions in the frontal lobes of several patients. Inspired by a study showing that chimpanzees became less prone to being agitated following frontal lobe resections, Moniz sought to sever white matter tracts between the frontal lobes and the rest of the brain via a process he called leucotomy, as he felt the frontal lobes were the source of agitation in mentally ill patients. Moniz was quick to defend h', 1, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "The procedure then took off in a major way thanks to American physician Walter Freeman and neurosurgeon James Watts"}, {"type": "citation_ref", "number": 103}, {"type": "text", "content": ". In 1942, they published the results from 200 “lobotomies.” They changed the named to emphasize the frontal lobes, indicate they were disturbing both white and grey matter, and distinguish themselves from Moniz"}, {"type": "citation_ref", "number": 103}, {"type": "text", "content": ". By interrupting “the connection between the frontal lobe and the thalamus” they claimed to reduce “the emotional reactions of the patient as regards himself,” and reintegrate the personality, all without a loss of intelligence"}, {"type": "citation_ref", "number": 104}, {"type": "text", "content": ". Eventually, Freeman developed a simplified, outpatient, transorbital technique that he could perform himself, using an ice pick, in an office setting. This procedure did not require a surgeon and it led to a breakdown in his partnership with Watts"}, {"type": "citation_ref", "number": 103}, {"type": "text", "content": ". Freeman travelled widely through the US, popularizing this method to treat mental illnesses ("}, {"type": "figure_placeholder", "number": "F"}, {"type": "text", "content": ")."}]}'::JSONB, 'The procedure then took off in a major way thanks to American physician Walter Freeman and neurosurgeon James Watts. In 1942, they published the results from 200 “lobotomies.” They changed the named to emphasize the frontal lobes, indicate they were disturbing both white and grey matter, and distinguish themselves from Moniz. By interrupting “the connection between the frontal lobe and the thalamus” they claimed to reduce “the emotional reactions of the patient as regards himself,” and reintegrate the personality, all without a loss of intelligence. Eventually, Freeman developed a simplified, ', 2, true, v_fig_f, 'auto', false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Over a 20-year period, lobotomies were performed on tens of thousands of patients worldwide"}, {"type": "citation_ref", "number": 100}, {"type": "text", "content": ". Moniz would go on to win the Nobel Prize for Medicine in 1949 for the “discovery of the therapeutic value of leucotomy in certain psychoses.” Psychosurgeries would fall from grace by the end of the 1950s, in part because of their questionable efficacy and frequent negative outcomes"}, {"type": "citation_ref", "number": 103}, {"type": "citation_ref", "number": 105}, {"type": "text", "content": ", but mostly because of the development of the first psychotropic drugs"}, {"type": "citation_ref", "number": 106}, {"type": "text", "content": "."}]}'::JSONB, 'Over a 20-year period, lobotomies were performed on tens of thousands of patients worldwide. Moniz would go on to win the Nobel Prize for Medicine in 1949 for the “discovery of the therapeutic value of leucotomy in certain psychoses.” Psychosurgeries would fall from grace by the end of the 1950s, in part because of their questionable efficacy and frequent negative outcomes, but mostly because of the development of the first psychotropic drugs.', 3, false, NULL, NULL, false, 0);

  -- Section: Electrical stimulation of the human brain: The story of Mary Rafferty
  INSERT INTO sections (module_id, title, slug, order_index)
  VALUES (v_module_id, 'Electrical stimulation of the human brain: The story of Mary Rafferty', 'box-electrical-stim', v_next_order)
  RETURNING id INTO v_section_id;
  v_next_order := v_next_order + 1;
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Rafferty and Roberts Bartholow"}]}'::JSONB, 'Rafferty and Roberts Bartholow', 0, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "January 26, 1874. A 30-year-old woman, Mary Rafferty, is admitted to the Good Samaritan Hospital in Cincinnati"}, {"type": "citation_ref", "number": 107}, {"type": "citation_ref", "number": 108}, {"type": "text", "content": ". She presents with a hole in her head due to a cancerous ulcer: “The skull itself is eroded and has disappeared over a space two inches in diameter, where the pulsations of the brain are plainly seen"}, {"type": "citation_ref", "number": 107}, {"type": "text", "content": " ("}, {"type": "figure_placeholder", "number": "G"}, {"type": "text", "content": "). Mary comes under the care of Dr. Roberts Bartholow. He is intrigued by the emerging field of electrotherapy and—having read of the experiments of Fritz and Hitzig, and Ferrier—realizes that Mary’s skull opening could allow him test out electrical stimulation in the human brain. In particular, Bartholow wants to see if he can repeat the results from dogs and monkeys, and drive motor movements in human via brain stimulation. He also wants to test out lateralization of function, and dural vs. cortical excitability. Though he later described Rafferty as “not very well nourished and rather feeble-minded,” he nonetheless sought and received her consent to perform brain stimulation experiments through her cranial cavity"}, {"type": "citation_ref", "number": 108}, {"type": "citation_ref", "number": 109}, {"type": "text", "content": "."}]}'::JSONB, 'January 26, 1874. A 30-year-old woman, Mary Rafferty, is admitted to the Good Samaritan Hospital in Cincinnati. She presents with a hole in her head due to a cancerous ulcer: “The skull itself is eroded and has disappeared over a space two inches in diameter, where the pulsations of the brain are plainly seen (Figure G)). Mary comes under the care of Dr. Roberts Bartholow. He is intrigued by the emerging field of electrotherapy and—having read of the experiments of Fritz and Hitzig, and Ferrier—realizes that Mary’s skull opening could allow him test out electrical stimulation in the human brai', 1, true, v_fig_g, 'auto', false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "On the first day of experiments, Bartholow had some initial success. Cortical stimulation provoked contralateral limb movements. To “develop more decided reactions,” Bartholow turned up the current, but this caused clonic spasms in Rafferty’s arm, emotional distress and crying. Rafferty then lost consciousness, during which time she exhibited convulsions. After recovering—still on this first day of experiments—Bartholow continued with stimulations, though at a lower current. A couple days later, Bartholow met again with Rafferty to continue with experiments. Her health, however, was in decline, and so the day’s activities were postponed. The following day, her condition was “decidedly worse.” She died soon afterwards, and Bartholow went on to publish a paper on his results"}, {"type": "citation_ref", "number": 107}, {"type": "text", "content": ". This was the first documented evidence of electrical stimulation of the human brain driving motor activity, but it drew considerable ethical concerns and Bartholow publicly sought to defend himself"}, {"type": "citation_ref", "number": 109}, {"type": "text", "content": ". It would be many years before electrical stimulation of the human brain picked back up, this time paired with resections related to epilepsy patients, pioneered by the likes of Otfrid Foerster, Harvey Cushing and Wilder Penfield."}]}'::JSONB, 'On the first day of experiments, Bartholow had some initial success. Cortical stimulation provoked contralateral limb movements. To “develop more decided reactions,” Bartholow turned up the current, but this caused clonic spasms in Rafferty’s arm, emotional distress and crying. Rafferty then lost consciousness, during which time she exhibited convulsions. After recovering—still on this first day of experiments—Bartholow continued with stimulations, though at a lower current. A couple days later, Bartholow met again with Rafferty to continue with experiments. Her health, however, was in decline', 2, false, NULL, NULL, false, 0);

  -- Section: Wilder Penfield and the Montreal Procedure
  INSERT INTO sections (module_id, title, slug, order_index)
  VALUES (v_module_id, 'Wilder Penfield and the Montreal Procedure', 'box-penfield', v_next_order)
  RETURNING id INTO v_section_id;
  v_next_order := v_next_order + 1;
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Wilder Penfield was born in Spokane, Washington in 1891. He obtained a Bachelor of Arts in Philosophy from Princeton before moving to Oxford as a Rhodes Scholar in the lab of Charles Sherrington, where he obtained a Bachelor of Science in Physiology. Penfield then completed medical training at Johns Hopkins University and apprenticed with Harvey Cushing"}, {"type": "citation_ref", "number": 110}, {"type": "text", "content": ". Penfield took his first job as a neurosurgeon in New York City, where he started working with William Vernon Cone, who would remain his neurosurgical partner for most of his professional career"}, {"type": "citation_ref", "number": 111}, {"type": "text", "content": ". While working with Cone to refine neurosurgical techniques, Penfield developed an interest in research related to epilepsy. As part of this endeavour, in 1924 he travelled to Spain—where he studied under Ramón y Cajal’s pupil Pio del Rio-Hortega—to learn methods for studying glial cells, which allowed him to examine glial tumours and brain scars"}, {"type": "citation_ref", "number": 112}, {"type": "text", "content": "."}]}'::JSONB, 'Wilder Penfield was born in Spokane, Washington in 1891. He obtained a Bachelor of Arts in Philosophy from Princeton before moving to Oxford as a Rhodes Scholar in the lab of Charles Sherrington, where he obtained a Bachelor of Science in Physiology. Penfield then completed medical training at Johns Hopkins University and apprenticed with Harvey Cushing. Penfield took his first job as a neurosurgeon in New York City, where he started working with William Vernon Cone, who would remain his neurosurgical partner for most of his professional career. While working with Cone to refine neurosurgical ', 0, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "In 1927, Penfield spent six months in Breslau, then part of Germany, to work with neurosurgeon Otfrid Foerster. Foerster had studied in Germany with Fedor Krause, who pioneered the use of electrical stimulation of cortex to guide removal of tissue resection as a treatment for epilepsy"}, {"type": "citation_ref", "number": 113}, {"type": "text", "content": ". Penfield was also aware that Cushing had briefly performed similar methods in a small number of patients around the turn of the century"}, {"type": "citation_ref", "number": 114}, {"type": "text", "content": ", and that Sherrington had performed related experiments in non-human primates"}, {"type": "citation_ref", "number": 115}, {"type": "text", "content": ". In Breslau, Penfield learned how to perform local cortical electrical stimulations while patients were treated with local anesthesia, as well as methods for excising brain scars"}, {"type": "citation_ref", "number": 112}, {"type": "text", "content": ". In 1928, after returning to New York City, Penfield, along with Cone, performed their version of the Foerster method for the first time, successfully treating an epilepsy patient"}, {"type": "citation_ref", "number": 112}, {"type": "text", "content": ". Later that year, Penfield and Cone moved to Montreal. In 1934, Penfield led the establishment of the Montreal Neurological Institute"}, {"type": "citation_ref", "number": 111}, {"type": "text", "content": ". There, along with Cone and many residents, Penfield continued refining the Foerster method and made it their own"}, {"type": "citation_ref", "number": 111}, {"type": "text", "content": ". They would carefully stimulate the brain surrounding an area where they thought the patient’s seizures were being generated. Then, if they were able to stimulate a seizure, they would carefully resect only the problematic piece of brain tissue. This became known as The Montreal Procedure (<strong>Figures H and I</strong>)."}]}'::JSONB, 'In 1927, Penfield spent six months in Breslau, then part of Germany, to work with neurosurgeon Otfrid Foerster. Foerster had studied in Germany with Fedor Krause, who pioneered the use of electrical stimulation of cortex to guide removal of tissue resection as a treatment for epilepsy. Penfield was also aware that Cushing had briefly performed similar methods in a small number of patients around the turn of the century, and that Sherrington had performed related experiments in non-human primates. In Breslau, Penfield learned how to perform local cortical electrical stimulations while patients ', 1, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "At the same time as they were performing this medical procedure, Penfield and colleagues began mapping the mind of awake patients. Upon stimulating a brain region, they would put a piece of paper with a number or letter on that brain area and note what the patient’s reaction was to the stimulation (<strong>Figures H and I</strong>). Some stimulations caused motor movements, some stimulations caused sensations, some stimulations even triggered memory recall"}, {"type": "citation_ref", "number": 116}, {"type": "text", "content": ". Most notably, Penfield carefully mapped the somatosensory and primary motor cortex, revealing an uneven representation of the body within each cortical area, similar to what had been predicted years earlier by neurologist John Hughlings Jackson who had studied the progression of motor movements during epileptic episodes"}, {"type": "citation_ref", "number": 117}, {"type": "text", "content": ". For instance, Penfield found that in somatosensory cortex the hands and lips had a much greater cortical representation than the back and legs ("}, {"type": "figure_placeholder", "number": "J"}, {"type": "text", "content": "). These uneven maps of the body in the brain are directly related to variations in the densities of primary sensory receptors in the skin. The visualization of this distorted map with an oddly shaped cartoon human is called a cortical homunculus (little man)."}]}'::JSONB, 'At the same time as they were performing this medical procedure, Penfield and colleagues began mapping the mind of awake patients. Upon stimulating a brain region, they would put a piece of paper with a number or letter on that brain area and note what the patient’s reaction was to the stimulation (Figures H and I). Some stimulations caused motor movements, some stimulations caused sensations, some stimulations even triggered memory recall. Most notably, Penfield carefully mapped the somatosensory and primary motor cortex, revealing an uneven representation of the body within each cortical are', 2, true, v_fig_j, 'auto', false, 0);

  -- Section: The developing brain: The discovery of nerve growth factor
  INSERT INTO sections (module_id, title, slug, order_index)
  VALUES (v_module_id, 'The developing brain: The discovery of nerve growth factor', 'box-ngf', v_next_order)
  RETURNING id INTO v_section_id;
  v_next_order := v_next_order + 1;
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "chemoaffinity"}]}'::JSONB, 'chemoaffinity', 0, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "Upon discovering axonal growth cones in the developing nervous system—which he referred to as “like a living battering-ram, soft and flexible, which advances mechanically, pushing aside the obstacles that it finds in its way until it reaches its peripheral destination”—Ramón y Cajal proposed a chemoaffinity, or “neurotropic” hypothesis to explain how axons figured out where to project"}, {"type": "citation_ref", "number": 118}, {"type": "text", "content": ". This was an astute prediction considering that Ramón y Cajal based it on static images he observed under his microscope."}]}'::JSONB, 'Upon discovering axonal growth cones in the developing nervous system—which he referred to as “like a living battering-ram, soft and flexible, which advances mechanically, pushing aside the obstacles that it finds in its way until it reaches its peripheral destination”—Ramón y Cajal proposed a chemoaffinity, or “neurotropic” hypothesis to explain how axons figured out where to project. This was an astute prediction considering that Ramón y Cajal based it on static images he observed under his microscope.', 1, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "In the 1950s, working at Washington University, first with Viktor Hamburger then with Stanley Cohen, Rita Levi-Montalcini made a series of breakthroughs that led to the discovery of the first-ever growth factor. Earlier, as a postgraduate student working in Turin, she had performed experiments which suggested that developing neurons required intact peripheral target tissues to survive"}, {"type": "citation_ref", "number": 119}, {"type": "text", "content": ". At Washington University, Levi-Montalcini set out to understand what the nature of this interaction between developing neuron and target area was. By implanting tumors into chick embryos, she found that the embryos showed overabundant nerve innervations, which she thought resulted from a substance generated from the implanted tumour. Then, working with Stanly Cohen who isolated the factor, which was named Nerve Growth Factor (or NGF), she found it to be a protein capable of promoting neurite outgrowth and neuron differentiation"}, {"type": "citation_ref", "number": 119}, {"type": "text", "content": ". Thus, consistent with Cajal’s hypothesis, there are specific external factors that neurons need to grow and develop. For this work, Rita Levi-Montalcini and Stanley Cohen were awarded the 1986 Nobel Prize in Physiology or Medicine."}]}'::JSONB, 'In the 1950s, working at Washington University, first with Viktor Hamburger then with Stanley Cohen, Rita Levi-Montalcini made a series of breakthroughs that led to the discovery of the first-ever growth factor. Earlier, as a postgraduate student working in Turin, she had performed experiments which suggested that developing neurons required intact peripheral target tissues to survive. At Washington University, Levi-Montalcini set out to understand what the nature of this interaction between developing neuron and target area was. By implanting tumors into chick embryos, she found that the embr', 2, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "However, if NGF was the only factor at play, it would be difficult for a growing axon to know which specific brain area to target. This is what led Roger Sperry, in the 1940s, to perform some quirky experiments in frogs"}, {"type": "citation_ref", "number": 120}, {"type": "text", "content": ". It was already known that in some lower vertebrates the optic nerve could be transected and subsequently regrown to support normal visual processing. In one experiment, Sperry removed a frog’s eye and rotated it 180 degrees upon re-implantation. He found that upon recovery, the frog could see again, but its visual behaviors and visuomotor reactions were inverted. In another experiment, whereas the frog’s optic nerves normally cross at the optic chiasm, in some animals he rewired them to stay ipsilateral. Similar to the eye rotation experiments, he found that some visual behaviors were inverted. He used this to put forward a chemoaffinity theory which postulated that a growing neuron contains a specificity tag which is shared with cells in the region it is meant to target"}, {"type": "citation_ref", "number": 120}, {"type": "text", "content": ". Similar to the work of Levi-Montalcini, Sperry’s chemoaffinity work was consistent with Cajal’s hypothesis that specific factors enable axons to develop and project to cell-type-specific target regions."}]}'::JSONB, 'However, if NGF was the only factor at play, it would be difficult for a growing axon to know which specific brain area to target. This is what led Roger Sperry, in the 1940s, to perform some quirky experiments in frogs. It was already known that in some lower vertebrates the optic nerve could be transected and subsequently regrown to support normal visual processing. In one experiment, Sperry removed a frog’s eye and rotated it 180 degrees upon re-implantation. He found that upon recovery, the frog could see again, but its visual behaviors and visuomotor reactions were inverted. In another ex', 3, false, NULL, NULL, false, 0);

  -- Section: Hippocrates: On the Sacred Disease ~400 BCE
  INSERT INTO sections (module_id, title, slug, order_index)
  VALUES (v_module_id, 'Hippocrates: On the Sacred Disease ~400 BCE', 'box-sacred-disease', v_next_order)
  RETURNING id INTO v_section_id;
  v_next_order := v_next_order + 1;
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "“It is thus with regard to the disease called Sacred [epilepsy]: it appears to me to be nowise more divine nor more sacred than other diseases, but has a natural cause from the originates like other affections… They who first referred this malady to the gods appear to me to have been just such persons as the conjurors, purificators, mountebanks, and charlatans now are, who give themselves out for being excessively religious, and as knowing more than other people. Such persons, then, using the divinity as a pretext and screen of their own inability to afford any assistance, have given out that the disease is sacred, adding suitable reasons for this opinion, they have instituted a mode of treatment which is safe for themselves, namely, by applying purifications and incantations, and enforcing abstinence from baths and many articles of food which are unwholesome to men in diseases… But this disease seems to me to be no more divine than others; but it has its nature such as other diseases have, and a cause whence it originates, and its nature and cause are divine only just as much as all others are, and it is curable no less than the others, unless when, the from of time, it is confirmed, and has became stronger than the remedies applied. Its origin is hereditary, like that of other diseases… But the brain is the cause of this affection, as it is of other very great diseases.”"}]}'::JSONB, '“It is thus with regard to the disease called Sacred [epilepsy]: it appears to me to be nowise more divine nor more sacred than other diseases, but has a natural cause from the originates like other affections… They who first referred this malady to the gods appear to me to have been just such persons as the conjurors, purificators, mountebanks, and charlatans now are, who give themselves out for being excessively religious, and as knowing more than other people. Such persons, then, using the divinity as a pretext and screen of their own inability to afford any assistance, have given out that ', 0, false, NULL, NULL, false, 0);
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "<em><strong>Figure</strong> <strong>K</strong></em>. Bust of Hippocrates from the British Museum. Source: The Wellcome Collection."}]}'::JSONB, 'Figure K. Bust of Hippocrates from the British Museum. Source: The Wellcome Collection.', 1, false, NULL, NULL, false, 0);

  -- Section: Humoral theory
  INSERT INTO sections (module_id, title, slug, order_index)
  VALUES (v_module_id, 'Humoral theory', 'box-humoral-theory', v_next_order)
  RETURNING id INTO v_section_id;
  v_next_order := v_next_order + 1;
  INSERT INTO paragraphs (section_id, content, content_text, order_index, has_animation, animation_id, animation_trigger, is_subsection_header, subsection_level)
  VALUES (v_section_id, '{"blocks": [{"type": "text", "content": "In ancient Greece, the Pythogoreans were mathematicians who were into numerology, and they had a particular reverence for the number four. Subsequently, Empedocles assembled a cosmology based on tetradic categories. The universe was comprised of four fundamental elements: earth, water, air and fire. There were four cosmic entities: sky, sun, earth and sea. There are four seasons: spring, summer, winter, fall. Hippocrates applied the four seasons to ages of human beings—childhood, youth, prime old age—and linked the four elements to four fundamental humors in the body: yellow bile, black bile, phlegm, and blood"}, {"type": "citation_ref", "number": 121}, {"type": "text", "content": " ("}, {"type": "figure_placeholder", "number": "K"}, {"type": "text", "content": "). Galen continued the Hippocratic medical practice of considering that illnesses and dispositions were caused by imbalances in the four humors, and patients were treated in a manner that sought to restore humoral balance. In practice, Galen felt that the palm of the hand was the best location to assess the balance of the humors"}, {"type": "citation_ref", "number": 121}, {"type": "text", "content": ". Humoral theory would go on to impact medical practice for well over a thousand years."}]}'::JSONB, 'In ancient Greece, the Pythogoreans were mathematicians who were into numerology, and they had a particular reverence for the number four. Subsequently, Empedocles assembled a cosmology based on tetradic categories. The universe was comprised of four fundamental elements: earth, water, air and fire. There were four cosmic entities: sky, sun, earth and sea. There are four seasons: spring, summer, winter, fall. Hippocrates applied the four seasons to ages of human beings—childhood, youth, prime old age—and linked the four elements to four fundamental humors in the body: yellow bile, black bile, ', 0, true, v_fig_k, 'auto', false, 0);

